from pathlib import Pathimport numpy as npimport pandas as pdimport jsonfrom petitRADTRANS.radtrans import Radtransfrom criresviz.common import OPACITYfrom config import (    MOLECULES,    OUTPUT,    TEMPERATURE,    PRESSURE,    WAVELENGTH_MIN,    WAVELENGTH_MAX,    TARGET_P,    TARGET_T,    c)def compute_opacity(species):    """    Compute the opacity spectrum of one molecule.    Parameters    ----------    species : str    Returns    -------    pandas.DataFrame    """    atmosphere = Radtrans(    pressures=PRESSURE,    line_species=[species],    wavelength_boundaries=np.array([WAVELENGTH_MIN, WAVELENGTH_MAX]),    line_opacity_mode="lbl",    )        pt_grid = (        atmosphere.lines_loaded_opacities        ["temperature_pressure_grid"][species]    )        distance = (        (pt_grid[:,0] - TARGET_T)**2        +        (np.log10(pt_grid[:,1]) - np.log10(TARGET_P))**2    )        index = np.argmin(distance)        opacity_grid = (atmosphere.lines_loaded_opacities["opacity_grid"][species])    opacity = opacity_grid[0, :, index]        wavelength_um = (c / atmosphere.frequencies) * 1e4    log_opacity = np.log10(opacity)    normalized = (log_opacity - log_opacity.min()) / (log_opacity.max() - log_opacity.min())    normalized /= normalized.max()    df = pd.DataFrame(        {            "wavelength_um": wavelength_um,            "opacity": opacity,            "normalized_opacity": normalized        }    )    return df            def save(df, species):    filename = OPACITY / f"{species}.csv"    df.to_csv(        filename,        index=False,    )    metadata = {        "species": species,        "temperature": TARGET_T,        "pressure": TARGET_P,        "pressure_unit": "Pa",        "wavelength_unit": "micron",        "opacity_mode": "lbl",        "source": "petitRADTRANS",    }    with open(        OPACITY / f"{species}.json",        "w"    ) as f:        json.dump(            metadata,            f,            indent=4,        )def main():    for species in MOLECULES:        print(f"Computing {species}")        df = compute_opacity(species)        save(df, species)if __name__ == "__main__":    main()